sql:
SELECT lib.library_name, env.environment_name
FROM image_libraries lib
JOIN server_environments env ON instr(env.supported_libraries, ',' || lib.library_name || ',') > 0;

external_knowledge:
- 'Linux' refers to a type of server environment; 
- 'Resize' refers to a specific image operation; 
- Image libraries are collections of images that can be used in various operations.

sql:
SELECT library_name, version, supported_operations, installation_instructions, dependencies
FROM image_libraries
WHERE library_name = 'ImageMagick' AND version = '7.1.0';

SELECT server_environments.environment_name, image_libraries.library_name 
FROM server_environments
JOIN image_libraries ON server_environments.supported_libraries = image_libraries.library_id;

SELECT environment_name
FROM server_environments
WHERE supported_libraries LIKE '%ImageMagick%';

SELECT 
    (SELECT COUNT(*) FROM image_libraries) AS total_libraries,
    (SELECT COUNT(*) FROM server_environments) AS total_environments;

SELECT COUNT(DISTINCT supported_libraries) AS unique_library_count
FROM server_environments
WHERE environment_id = 201;

SELECT DISTINCT supported_libraries
FROM image_operations
ORDER BY operation_name ASC;

SELECT environment_name, default_file_permissions 
FROM server_environments 
WHERE supported_libraries LIKE '%ImageMagick%';

SELECT library_id, library_name, version, supported_operations, installation_instructions, dependencies
FROM image_libraries
WHERE supported_operations LIKE '%ImageMagick%';

SELECT library_name, version, supported_operations
FROM image_libraries
ORDER BY library_name;

SELECT DISTINCT se.supported_libraries AS library_names
FROM server_environments se
WHERE se.operating_system = 'Ubuntu 20.04';

SELECT io.operation_name
FROM image_operations io
WHERE io.supported_libraries GLOB '*ImageMagick*';
